    /**
     * Specifies the type of traversal performed by `g_tree_traverse()`,
     * `g_node_traverse()` and `g_node_find()`.
     *
     * The different orders are illustrated here:
     *
     * - In order: A, B, C, D, E, F, G, H, I
     *   <picture>
     *     <source srcset="https://docs.gtk.org/glib/Sorted_binary_tree_inorder-dark.svg"
     *      media="(prefers-color-scheme: dark)">
     *     <img src="https://docs.gtk.org/glib/Sorted_binary_tree_inorder.svg"
     *      alt="Sorted binary tree, in-order traversal">
     *   </picture>
     * - Pre order: F, B, A, D, C, E, G, I, H
     *   <picture>
     *     <source srcset="https://docs.gtk.org/glib/Sorted_binary_tree_preorder-dark.svg"
     *      media="(prefers-color-scheme: dark)">
     *     <img src="https://docs.gtk.org/glib/Sorted_binary_tree_preorder.svg"
     *      alt="Sorted binary tree, pre-order traversal">
     *   </picture>
     * - Post order: A, C, E, D, B, H, I, G, F
     *   <picture>
     *     <source srcset="https://docs.gtk.org/glib/Sorted_binary_tree_postorder-dark.svg"
     *      media="(prefers-color-scheme: dark)">
     *     <img src="https://docs.gtk.org/glib/Sorted_binary_tree_postorder.svg"
     *      alt="Sorted binary tree, post-order traversal">
     *   </picture>
     * - Level order: F, B, G, A, D, I, C, E, H
     *   <picture>
     *     <source srcset="https://docs.gtk.org/glib/Sorted_binary_tree_breadth-first_traversal-dark.svg"
     *      media="(prefers-color-scheme: dark)">
     *     <img src="https://docs.gtk.org/glib/Sorted_binary_tree_breadth-first_traversal.svg"
     *      alt="Sorted binary tree, breadth-first level order traversal">
     *   </picture>
     * @gir-type Enum
     */
    enum TraverseType {
        /**
         * visits a node's left child first, then the node itself,
         *              then its right child. This is the one to use if you
         *              want the output sorted according to the compare
         *              function.
         */
        IN_ORDER,
        /**
         * visits a node, then its children.
         */
        PRE_ORDER,
        /**
         * visits the node's children, then the node itself.
         */
        POST_ORDER,
        /**
         * is not implemented for
         *              [balanced binary trees](https://docs.gtk.org/glib/data-structures.html#binary-trees).
         *              For [n-ary trees](https://docs.gtk.org/glib/data-structures.html#n-ary-trees), it
         *              visits the root node first, then its children, then
         *              its grandchildren, and so on. Note that this is less
         *              efficient than the other orders.
         */
        LEVEL_ORDER,
    }

