    /**
     * These are the possible character classifications from the
     * Unicode specification.
     * See [Unicode Character Database](http://www.unicode.org/reports/tr44/#General_Category_Values).
     * @gir-type Enum
     */
    enum UnicodeType {
        /**
         * General category "Other, Control" (Cc)
         */
        CONTROL,
        /**
         * General category "Other, Format" (Cf)
         */
        FORMAT,
        /**
         * General category "Other, Not Assigned" (Cn)
         */
        UNASSIGNED,
        /**
         * General category "Other, Private Use" (Co)
         */
        PRIVATE_USE,
        /**
         * General category "Other, Surrogate" (Cs)
         */
        SURROGATE,
        /**
         * General category "Letter, Lowercase" (Ll)
         */
        LOWERCASE_LETTER,
        /**
         * General category "Letter, Modifier" (Lm)
         */
        MODIFIER_LETTER,
        /**
         * General category "Letter, Other" (Lo)
         */
        OTHER_LETTER,
        /**
         * General category "Letter, Titlecase" (Lt)
         */
        TITLECASE_LETTER,
        /**
         * General category "Letter, Uppercase" (Lu)
         */
        UPPERCASE_LETTER,
        /**
         * General category "Mark, Spacing" (Mc)
         */
        SPACING_MARK,
        /**
         * General category "Mark, Enclosing" (Me)
         */
        ENCLOSING_MARK,
        /**
         * General category "Mark, Nonspacing" (Mn)
         */
        NON_SPACING_MARK,
        /**
         * General category "Number, Decimal Digit" (Nd)
         */
        DECIMAL_NUMBER,
        /**
         * General category "Number, Letter" (Nl)
         */
        LETTER_NUMBER,
        /**
         * General category "Number, Other" (No)
         */
        OTHER_NUMBER,
        /**
         * General category "Punctuation, Connector" (Pc)
         */
        CONNECT_PUNCTUATION,
        /**
         * General category "Punctuation, Dash" (Pd)
         */
        DASH_PUNCTUATION,
        /**
         * General category "Punctuation, Close" (Pe)
         */
        CLOSE_PUNCTUATION,
        /**
         * General category "Punctuation, Final quote" (Pf)
         */
        FINAL_PUNCTUATION,
        /**
         * General category "Punctuation, Initial quote" (Pi)
         */
        INITIAL_PUNCTUATION,
        /**
         * General category "Punctuation, Other" (Po)
         */
        OTHER_PUNCTUATION,
        /**
         * General category "Punctuation, Open" (Ps)
         */
        OPEN_PUNCTUATION,
        /**
         * General category "Symbol, Currency" (Sc)
         */
        CURRENCY_SYMBOL,
        /**
         * General category "Symbol, Modifier" (Sk)
         */
        MODIFIER_SYMBOL,
        /**
         * General category "Symbol, Math" (Sm)
         */
        MATH_SYMBOL,
        /**
         * General category "Symbol, Other" (So)
         */
        OTHER_SYMBOL,
        /**
         * General category "Separator, Line" (Zl)
         */
        LINE_SEPARATOR,
        /**
         * General category "Separator, Paragraph" (Zp)
         */
        PARAGRAPH_SEPARATOR,
        /**
         * General category "Separator, Space" (Zs)
         */
        SPACE_SEPARATOR,
    }

    /**
     * Error codes returned by {@link GLib.Uri} methods.
     * @gir-type Struct
     */
    class UriError extends Error {
        static $gtype: GObject.GType<Error>;

        // Static fields

        /**
         * Generic error if no more specific error is available.
         *     See the error message for details.
         */
        static FAILED: number;
        /**
         * The scheme of a URI could not be parsed.
         */
        static BAD_SCHEME: number;
        /**
         * The user/userinfo of a URI could not be parsed.
         */
        static BAD_USER: number;
        /**
         * The password of a URI could not be parsed.
         */
        static BAD_PASSWORD: number;
        /**
         * The authentication parameters of a URI could not be parsed.
         */
        static BAD_AUTH_PARAMS: number;
        /**
         * The host of a URI could not be parsed.
         */
        static BAD_HOST: number;
        /**
         * The port of a URI could not be parsed.
         */
        static BAD_PORT: number;
        /**
         * The path of a URI could not be parsed.
         */
        static BAD_PATH: number;
        /**
         * The query of a URI could not be parsed.
         */
        static BAD_QUERY: number;
        /**
         * The fragment of a URI could not be parsed.
         */
        static BAD_FRAGMENT: number;

        // Constructors

        constructor(options: { message: string; code: number });
    }

    /**
     * These are logical ids for special directories which are defined
     * depending on the platform used. You should use `g_get_user_special_dir()`
     * to retrieve the full path associated to the logical id.
     *
     * The {@link GLib.UserDirectory} enumeration can be extended at later date. Not
     * every platform has a directory for every logical id in this
     * enumeration.
     * @gir-type Enum
     * @since 2.14
     */
    enum UserDirectory {
        /**
         * the user's Desktop directory
         */
        DIRECTORY_DESKTOP,
        /**
         * the user's Documents directory
         */
        DIRECTORY_DOCUMENTS,
        /**
         * the user's Downloads directory
         */
        DIRECTORY_DOWNLOAD,
        /**
         * the user's Music directory
         */
        DIRECTORY_MUSIC,
        /**
         * the user's Pictures directory
         */
        DIRECTORY_PICTURES,
        /**
         * the user's shared directory
         */
        DIRECTORY_PUBLIC_SHARE,
        /**
         * the user's Templates directory
         */
        DIRECTORY_TEMPLATES,
        /**
         * the user's Movies directory
         */
        DIRECTORY_VIDEOS,
        /**
         * the number of enum values
         */
        N_DIRECTORIES,
    }

    /**
     * The range of possible top-level types of {@link GLib.Variant} instances.
     * @gir-type Enum
     * @since 2.24
     */
    enum VariantClass {
        /**
         * The {@link GLib.Variant} is a boolean.
         */
        BOOLEAN,
        /**
         * The {@link GLib.Variant} is a byte.
         */
        BYTE,
        /**
         * The {@link GLib.Variant} is a signed 16 bit integer.
         */
        INT16,
        /**
         * The {@link GLib.Variant} is an unsigned 16 bit integer.
         */
        UINT16,
        /**
         * The {@link GLib.Variant} is a signed 32 bit integer.
         */
        INT32,
        /**
         * The {@link GLib.Variant} is an unsigned 32 bit integer.
         */
        UINT32,
        /**
         * The {@link GLib.Variant} is a signed 64 bit integer.
         */
        INT64,
        /**
         * The {@link GLib.Variant} is an unsigned 64 bit integer.
         */
        UINT64,
        /**
         * The {@link GLib.Variant} is a file handle index.
         */
        HANDLE,
        /**
         * The {@link GLib.Variant} is a double precision floating
         *                          point value.
         */
        DOUBLE,
        /**
         * The {@link GLib.Variant} is a normal string.
         */
        STRING,
        /**
         * The {@link GLib.Variant} is a D-Bus object path
         *                               string.
         */
        OBJECT_PATH,
        /**
         * The {@link GLib.Variant} is a D-Bus signature string.
         */
        SIGNATURE,
        /**
         * The {@link GLib.Variant} is a variant.
         */
        VARIANT,
        /**
         * The {@link GLib.Variant} is a maybe-typed value.
         */
        MAYBE,
        /**
         * The {@link GLib.Variant} is an array.
         */
        ARRAY,
        /**
         * The {@link GLib.Variant} is a tuple.
         */
        TUPLE,
        /**
         * The {@link GLib.Variant} is a dictionary entry.
         */
        DICT_ENTRY,
    }

    /**
     * Error codes returned by parsing text-format GVariants.
     * @gir-type Struct
     */
    class VariantParseError extends Error {
        static $gtype: GObject.GType<Error>;

        // Static fields

        /**
         * generic error (unused)
         */
        static FAILED: number;
        /**
         * a non-basic {@link GLib.VariantType} was given where a basic type was expected
         */
        static BASIC_TYPE_EXPECTED: number;
        /**
         * cannot infer the {@link GLib.VariantType}
         */
        static CANNOT_INFER_TYPE: number;
        /**
         * an indefinite {@link GLib.VariantType} was given where a definite type was expected
         */
        static DEFINITE_TYPE_EXPECTED: number;
        /**
         * extra data after parsing finished
         */
        static INPUT_NOT_AT_END: number;
        /**
         * invalid character in number or unicode escape
         */
        static INVALID_CHARACTER: number;
        /**
         * not a valid {@link GLib.Variant} format string
         */
        static INVALID_FORMAT_STRING: number;
        /**
         * not a valid object path
         */
        static INVALID_OBJECT_PATH: number;
        /**
         * not a valid type signature
         */
        static INVALID_SIGNATURE: number;
        /**
         * not a valid {@link GLib.Variant} type string
         */
        static INVALID_TYPE_STRING: number;
        /**
         * could not find a common type for array entries
         */
        static NO_COMMON_TYPE: number;
        /**
         * the numerical value is out of range of the given type
         */
        static NUMBER_OUT_OF_RANGE: number;
        /**
         * the numerical value is out of range for any type
         */
        static NUMBER_TOO_BIG: number;
        /**
         * cannot parse as variant of the specified type
         */
        static TYPE_ERROR: number;
        /**
         * an unexpected token was encountered
         */
        static UNEXPECTED_TOKEN: number;
        /**
         * an unknown keyword was encountered
         */
        static UNKNOWN_KEYWORD: number;
        /**
         * unterminated string constant
         */
        static UNTERMINATED_STRING_CONSTANT: number;
        /**
         * no value given
         */
        static VALUE_EXPECTED: number;
        /**
         * variant was too deeply nested; {@link GLib.Variant} is only guaranteed to handle nesting up to 64 levels (Since: 2.64)
         */
        static RECURSION: number;

        // Constructors

        constructor(options: { message: string; code: number });
    }

